void postOrder(Node* root) {
    if (root == NULL) return;

    Node** st1 = (Node**)malloc(sizeof(Node*) * 100000);
    Node** st2 = (Node**)malloc(sizeof(Node*) * 100000);
    int top1 = -1, top2 = -1;
    st1[++top1] = root;

    while (top1 != -1) {
        root = st1[top1--];
        st2[++top2] = root;
        if (root->left) st1[++top1] = root->left;
        if (root->right) st1[++top1] = root->right;
