        this.val = x;  // The value of the node
        this.left = null;  // Pointer to the left child
        this.right = null;  // Pointer to the right child
    }
}

// Function to perform postorder traversal of a binary tree iteratively
function postOrder(root) {
    let postorder = [];  // Array to store the postorder traversal result

    // If the tree is empty, return an empty traversal
    if (root === null) {
        return postorder;
    }

    let st1 = [];  // First stack for iterative traversal
    let st2 = [];  // Second stack to store nodes in postorder

    // Push the root node onto the first stack
    st1.push(root);

    // Iterative traversal to populate st2 with nodes in postorder
    while (st1.length > 0) {
        root = st1.pop();  // Get the top node from st1
        st2.push(root);  // Push the node onto st2

        // Push left child onto st1 if exists
        if (root.left) {
            st1.push(root.left);
        }

        // Push right child onto st1 if exists
        if (root.right) {
            st1.push(root.right);
        }
    }

    // Populate the postorder traversal result by popping st2
    while (st2.length > 0) {
        postorder.push(st2.pop().val);  // Add the node's value to the postorder result
    }

    // Return the postorder traversal result
    return postorder;
}

